  "rgb(220, 0, 0)",
  "rgb(0, 160, 160)",
  "rgb(180, 0, 180)",
  "rgb(170, 140, 0)",
  "rgb(220, 120, 0)",
  "rgb(128, 128, 128)",
  "rgb(100, 0, 180)",
  "rgb(140, 70, 0)",
  "rgb(220, 80, 120)",
