import { copperPourProps } from "@tscircuit/props";
import {
  CopperPourPipelineSolver as CopperPourPipelineSolver2,
  convertCircuitJsonToInputProblem,
  initializeManifoldGeometry
} from "@tscircuit/copper-pour-solver";
